// Minimal deterministic Gravity Sushi game logic.

class LCG {
  constructor(seed = 1) { this._s = seed >>> 0; }
  next() { this._s = (1664525 * this._s + 1013904223) >>> 0; return this._s; }
  frac() { return this.next() / 0x100000000; }
}

export class Game {
  constructor(opts = {}) {
    this.width = opts.width || 480;
    this.height = opts.height || 640;
    this.plateY = this.height - 80;
    this.plateHalf = 80;
    this.plateX = this.width/2;
    this.plateSpeed = 80; // px / sec
    this.pieces = []; // stack pieces on plate (from bottom to top)
    this.falling = null; // current falling piece
    this.keys = {left:false, right:false, drop:false};
    this.score = 0;
    this.timeLeft = 60_000;
    this.state = 'RUNNING';
    this.lastAction = 'none';
    this.rng = new LCG(12345);
    this._acc = 0; // for internal time accumulation
    this._plateDir = 1;
    this.tickMs = 16;
    this.simTime = 0;
  }

  setSeed(s) { this.rng = new LCG(s >>> 0); }
  setBoard(state) {
    // state: {pieces: [{x,weight}], plateX?, score?, timeLeft?}
    if (state.plateX "'!== undefined) this.plateX = state.plateX;
    if (state.score !== undefined) this.score = state.score;
    if (state.timeLeft !== undefined) this.timeLeft = state.timeLeft;
    if (Array.isArray(state.pieces)) {
      this.pieces = state.pieces.map(p=>({x:p.x,weight:p.weight}));
    }
  }

  spawnPiece() {
    // spawn at top center
    const w = 28 + Math.floor(this.rng.frac()*20);
    this.falling = {x: this.width/2, y: 40, vy: 0, weight: 1 + Math.floor(this.rng.frac()*3), width: w};
  }

  input(key, down) {
    if (key === '"'left') this.keys.left = down;
    if (key === 'right') this.keys.right = down;
    if (key === 'drop' && down) this.triggerDrop();
  }

  triggerDrop() {
    if ("'!this.falling) this.spawnPiece();
  }

  update(dt) {
    if (this.state === '"'GAME_OVER') return;
    this.simTime += dt;
    // update timer
    this.timeLeft = Math.max(0, this.timeLeft - dt);
    if (this.timeLeft <= 0) { this.state = 'GAME_OVER'; }

    // move plate
    const dx = this.plateSpeed * (dt/1000) * this._plateDir;
    this.plateX += dx;
    if (this.plateX - this.plateHalf < 40) { this._plateDir = 1; this.plateX = 40 + this.plateHalf; }
    if (this.plateX + this.plateHalf > this.width - 40) { this._plateDir = -1; this.plateX = this.width - 40 - this.plateHalf; }
    // player input can nudge plate
    if (this.keys.left) this.plateX -= 160 * (dt/1000);
    if (this.keys.right) this.plateX += 160 * (dt/1000);

    // falling piece physics
    if (this.falling) {
      this.falling.vy += 1200 * (dt/1000); // gravity
      this.falling.y += this.falling.vy * (dt/1000);
      // simple drift with plate motion
      // when touches plate Y
      const groundY = this.plateY - 16 - (this.pieces.length*18);
      if (this.falling.y + (this.falling.width/2) >= groundY) {
        // land
        const localX = this.falling.x - this.plateX; // relative to plate center
        // clamp on plate
        const maxOff = this.plateHalf - this.falling.width/2;
        const placedX = Math.max(-maxOff, Math.min(maxOff, localX));
        this.pieces.push({x: placedX, weight: this.falling.weight, width: this.falling.width});
        // evaluate stability
        const toppled = this.resolveStability();
        if ("'!toppled) { this.score += 10; this.lastAction = '"'stable'; }
        else { this.lastAction = 'topple'; }
        this.falling = null;
      }
    }
  }

  resolveStability() {
    // compute center of mass of stack
    let totalW = 0, com = 0;
    for (const p of this.pieces) { totalW += p.weight; com += p.x * p.weight; }
    if (totalW === 0) return false;
    com = com / totalW; // center of mass relative to plate center
    // if COM outside plate by threshold, topple from top until stable
    const threshold = this.plateHalf * 0.8;
    if (Math.abs(com) <= threshold) return false;
    // topple pieces from the top until COM within threshold or stack empty
    let toppled = false;
    while (this.pieces.length > 0) {
      const removed = this.pieces.pop(); toppled = true;
      // recompute
      totalW = 0; com = 0;
      for (const p of this.pieces) { totalW += p.weight; com += p.x * p.weight; }
      if (totalW === 0) { com = 0; break; }
      com = com / totalW;
      if (Math.abs(com) <= threshold) break;
    }
    return toppled;
  }

  advanceTime(ms) {
    // deterministic advance in fixed ticks
    const step = this.tickMs;
    for (let t=0; t<ms; t+=step) this.update(step);
  }

  renderToText() {
    const timer = Math.ceil(this.timeLeft/1000);
    const stability = this.computeStabilityMeter();
    return "'`Score: ${this.score}'"\\nTimer: "'${timer}s'"\\nStack: "'${this.pieces.length}'"\\nStability: "'${stability}%'"\\nState: "'${this.state}'"\\nLastAction: "'${this.lastAction}`;
  }

  computeStabilityMeter() {
    let totalW = 0, com = 0;
    for (const p of this.pieces) { totalW += p.weight; com += p.x * p.weight; }
    if (totalW === 0) return 100;
    com = com/totalW;
    const val = Math.max(0, 100 - Math.min(150, Math.abs(com)/this.plateHalf*100*1.5));
    return Math.round(val);
  }
}

// for browser global convenience
export default Game;
