import Game from './game.js';

// The code is written in TS-style but intends to be plain JS-compatible when transpiled.
const canvas = document.getElementById('game');
const debug = document.getElementById('debug');
const ctx = canvas.getContext('2d');
const game = new Game({width: canvas.width, height: canvas.height});

// expose deterministic hooks
window['__game_instance'] = game;
window.advanceTime = (ms) => { game.advanceTime(ms); updateDebug(); };
window.render_game_to_text = () => game.renderToText();
window.setSeed = (s) => { game.setSeed(s); };
window.setBoard = (b) => { game.setBoard(b); };

// keyboard
window.addEventListener('keydown', (e) => {
  if (e.key === 'ArrowLeft') game.input('left', true);
  if (e.key === 'ArrowRight') game.input('right', true);
  if (e.key === ' ' || e.key === 'Spacebar') game.input('drop', true);
});
window.addEventListener('keyup', (e) => {
  if (e.key === 'ArrowLeft') game.input('left', false);
  if (e.key === 'ArrowRight') game.input('right', false);
});

function updateDebug() {
  debug.textContent = game.renderToText();
}

// simple render loop
function render() {
  // clear
  ctx.fillStyle = '#111'; ctx.fillRect(0,0,canvas.width,canvas.height);
  // plate
  ctx.fillStyle = '#884'; const px = game.plateX - game.plateHalf; ctx.fillRect(px, game.plateY, game.plateHalf*2, 12);
  // stack
  let y = game.plateY - 16;
  for (const p of game.pieces) {
    ctx.fillStyle = '#f5a';
    ctx.fillRect(game.plateX + p.x - p.width/2, y - 16, p.width, 16);
    y -= 18;
  }
  // falling
  if (game.falling) {
    ctx.fillStyle = '#afa';
    ctx.fillRect(game.falling.x - game.falling.width/2, game.falling.y - game.falling.width/2, game.falling.width, 16);
  }
  // HUD
  ctx.fillStyle = '#ddd'; ctx.font = '14px monospace'; ctx.fillText("'`Score: ${game.score}`, 12, 20);
  ctx.fillText(`Time: ${Math.ceil(game.timeLeft/1000)}s`, 12, 40);
  // loop
  requestAnimationFrame(render);
}
render();

// advance internal simulation regularly (non-deterministic runner for UI)
let last = performance.now();
function tick(now) {
  const dt = Math.min(100, now - last); last = now;
  if (game.state !== '"'GAME_OVER') game.update(dt);
  updateDebug();
  requestAnimationFrame(tick);
}
requestAnimationFrame(()=>{ last = performance.now(); tick(last); });

export {};
