import { test, expect } from '@playwright/test';
import path from 'path';

const fileUrl = (name: string) => 'file://' + path.join(__dirname, '..', name);

test('score increases on stable drops', async ({ page }) => {
  await page.goto(fileUrl('index.html'));
  // set deterministic seed and empty board
  await page.evaluate(() => { window.setSeed(42); window.setBoard({pieces: [], score:0, timeLeft:60000}); });
  // trigger a drop and advance time enough to land
  await page.evaluate(() => { window.advanceTime(2000); });
  const txt = await page.evaluate(() => window.render_game_to_text());
  expect(txt).toContain('Score: 10');
  expect(txt).toContain('LastAction: stable');
});

test('topple trigger reduces stack', async ({ page }) => {
  await page.goto(fileUrl('index.html'));
  // set board with heavy offsets that will topple when a new piece lands off-center
  await page.evaluate(() => {
    window.setSeed(123);
    window.setBoard({ pieces: [ {x: 60, weight:3}, {x:60, weight:2} ], score:0, timeLeft:60000 });
  });
  await page.evaluate(() => { window.advanceTime(2000); });
  const txt = await page.evaluate(() => window.render_game_to_text());
  // topple should have occurred
  expect(txt).toContain('LastAction: topple');
});

test('timer causes game over', async ({ page }) => {
  await page.goto(fileUrl('index.html'));
  await page.evaluate(() => { window.setSeed(1); window.setBoard({pieces: [], score:0, timeLeft:500}); });
  await page.evaluate(() => { window.advanceTime(2000); });
  const txt = await page.evaluate(() => window.render_game_to_text());
  expect(txt).toContain('State: GAME_OVER');
});
